var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"감옥에 갇힌 죄수들은 죄목으로 자기들 사이에서 급을 나눠.","JPN":"刑務所に入った囚人たちは、罪の重さでランク付けをする。","ENG":"In prison, the inmates discriminate among each other based on their charges.","TWN":"被關在監獄裡的囚犯會以罪名分等級。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"선량한 시민들 눈에는 다 죽일 놈들인데, 살인자는 피해야 될 놈이고 아동 납치범은 맞아도 싼 놈 취급 받지.","JPN":"善良な市民からしたら全員凶悪な犯罪者なのに、人殺しは避けるべき者で、児童誘拐犯は殴られて当然の扱いをされる。","ENG":"To innocent civilians, they are all just criminals. But they too avoid murderers, and think it's fair game to beat up pedophiles anytime they want.","TWN":"他們都是罪該萬死的人，但在善良的市民眼中，殺人犯是需要避開的人，而兒童綁架犯就算挨打也不會得到原諒。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"남의 자식 목숨 값 흥정하는 건 더럽고, 배신자의 일가족을 물고기 밥으로 만드는 건 대단한가?","JPN":"他人の子どもの命を利用するのは汚らわしいことで、裏切り者の一家を魚の餌にするのは見事なことだって？","ENG":"But who's to say what crime is worthy of respect and what's worthy of disdain?","TWN":"用別人孩子的性命討價還價是骯髒的行為，但把背叛者一家丟去餵魚就了不起了嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"사실은 다들 알고 있어.","JPN":"実はみんなわかっているんだ。","ENG":"Everyone knows there's no difference.","TWN":"其實大家都知道。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그냥 걱정 없이 물어뜯으면서 스트레스 풀 샌드백이 필요해서지.","JPN":"ただ心置きなく噛みちぎってストレスを発散できるサンドバッグが必要なだけ。","ENG":"They just want a punching bag to relieve their stress upon.","TWN":"他們不過是需要一個可以放心抒發壓力的沙包而已……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 그 연놈들한테 유난스럽게 굴었던 것도......","JPN":"私があいつらに大げさになっていたのも……","ENG":"I was probably extra dramatic with those fools...","TWN":"我特別對待的那對狗男女也……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"아마 비슷한 이유였을 거야.","JPN":"おそらく似たような理由だろう。","ENG":"... for a similar reason.","TWN":"大概也是差不多的理由吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"어윽......!","JPN":"くっ……！","ENG":"Ugh!","TWN":"呃……！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"다...... 다짜고짜 사람을 끌고 와? 당신 이거 범죄야!","JPN":"む……無理やり人を連れていくなんて、これは立派な犯罪だぞ！","ENG":"Hey... You can't just drag us out here! This is a crime, you know!","TWN":"就……就這樣不分青紅皂白的把人拉過來？你這樣是犯罪！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"맞아! 그 자리는 우리가 사흘 전부터 찍어 뒀던 명당이라고!","JPN":"そうよ！　あそこは私たちが3日前から狙っていたアタリの場所なの！","ENG":"That's right! We had dibs on that spot three days ago!","TWN":"對！那個位置是我們三天前就定好的地方！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"거기서 몇 명이 대박을 터뜨렸는데......!","JPN":"そこで何人も大勝ちしたと聞いて……！　","ENG":"So many people hit the jackpot there!","TWN":"坐在那裡有好幾個人都發大財了……！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":" 끄윽......!","JPN":"くうっ……！","ENG":" Ow!","TWN":"呃啊……！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L18_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"여, 여보!","JPN":"あ、あなた！","ENG":"H-honey!","TWN":"老、老婆！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 댁들처럼 간이 배 밖으로 나온 인간들이 제일 신기해.","JPN":"私はな、お前らみたいな人間が一番不思議でしょうがないんだ。","ENG":"I'm always amazed by how quickly people forget fear.","TWN":"我很好奇你們這些膽大包天的人類。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 도박이 좋나? 지난달에는 욕조에서 입수도 시켜 줬는데?","JPN":"そんなにギャンブルが好きか？　先月みたいにまた水責めにされたいのか？","ENG":"Do you love gambling that much? Even after I water-boarded you last month?","TWN":"就那麼想發財？上個月才被我按在浴缸裡醒腦！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무튼, 이번 달치 상환금은 약속대로 내놓으셔야겠어.","JPN":"とにかく、今月分の償還金は約束どおりもらうぞ。","ENG":"In any case, you'd better cough up this month's payment as promised.","TWN":"總之，這個月的還款一定要如期交出來。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그, 글쎄 따서 갚는다니까......","JPN":"だ、だから勝ったら返すって……","ENG":"W-we will, once we win some money...","TWN":"我、我們贏了錢就還……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"이런 식으로 자꾸 빚 갚는 데 방해하니까 그렇지! 당신 계속 이러면 고소할 거야!","JPN":"今みたいにあんたが借金返済を邪魔するからよ！　またこんなことしたら訴えてやるからね！","ENG":"We're trying to earn some money to pay you back, but you keep getting in the way! We're going to sue you if you keep doing this!","TWN":"因為你總是這樣妨礙我們還債啊！你再這樣我就要告你了！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"해 볼 테면 해 봐. 법보다 주먹이 가깝다는 말이 무슨 뜻인지 알려 주지.","JPN":"やれるものならやってみろ。\\n「太鼓が鳴り響く所では、法の声は聞えない」という言葉の意味を教えてやる。","ENG":"Be my guest. You'll find out the pen isn't mightier than the sword after all. Or rather, the fist.","TWN":"隨便。到時就讓你知道拳頭和法律哪個更硬。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"누...... 누가 그러면 무서워할 줄 알고!","JPN":"そ、そんな言葉で脅しても怖くなんかないわよ！","ENG":"You... You think you can scare us like that?","TWN":"以……以為你這麼說我們就怕你嗎！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"그렇게 돈에 목매달면 오래 못 살아, 어?!","JPN":"あんたみたいに金ばっかり追いかけたら、ろくな死に方しないからね！","ENG":"You'll get yourself killed if you obsess over money so much, you hear?!","TWN":"每天錢錢錢，活不長久的，知道嗎？！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......썩어 가는 늙은이들이라 참 곤란하다니까.","JPN":"……落ちるところまで落ちた老害のくせに、本当に手こずらせてくれるな。","ENG":"It's always a pain in the butt dealing with old fools like you.","TWN":"……一群老狐狸，還好意思說我。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돈 나올 구석도 없는 것들이 차명으로 빌리기나 하고.","JPN":"金の出どころも無ければ、借名取引までしやがって。","ENG":"Especially when you keep borrowing more money under other people's names.","TWN":"明明沒錢，卻用假名去借。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"아휴, 그러지 말고 조금만 기다려 봐. 대박 한 번 터지면 배당이 얼만데.","JPN":"だから、少しだけ待ってくれと言ったじゃないか。\\n一発当たればデカい配当が獲れるんだからさ。","ENG":"Oh come on. Just give us a few more days. This next jackpot is going to be huge.","TWN":"哎喲，別這樣，再寬容幾天。只要賭贏了分紅非常可觀。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대박이든 쪽박이든 나는 받을 돈만 받으면 돼.","JPN":"大当たりだのクソ当たりだの、私は借金だけ返してもらえればいい。","ENG":"I couldn't care less about your jackpot. I'm just here to collect this month's payment.","TWN":"贏不贏的我不管，我只要我應該拿的那一份。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러니 이렇게 하지. 담보를 내놔.","JPN":"だからこうしよう。担保を出せ。","ENG":"I'll tell you what, then. Just give me a collateral.","TWN":"那這樣吧，拿東西抵押吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"헤헤...... 그, 그게 집이나 차나 잡을 수 있는 건 이미 다 잡혀 있는데요.","JPN":"へへ……そ、それが家も車もすでに銀行と業者に預けているんだ。","ENG":"Heh... W-well, anything of value we've got has already been taken as collateral. Our house, our car...","TWN":"嘿嘿……不管是房子還是車，能抵押的已經全都抵押了。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"아이고, 사람들이 인정머리도 없다니까요. 나중에 잘되면 어떡하려고 참.","JPN":"まったく、本当に人情のない奴ばかりだ。これからうまくいくかもしれないのに。","ENG":"Those bankers can be so heartless, I tell you. They'll be sorry when we're rich!","TWN":"哎呀呀，你也太不講情面了。我們將來若是發達了，看你怎麼說。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"팔아 봤자 몇 푼 나오지도 않을 고물들에는 관심 없어.","JPN":"売っても二束三文にもならないものには興味ない。","ENG":"I'm not interested in your junk; that'll only fetch me peanuts.","TWN":"我對那些賣了也值不了幾個錢的破爛沒興趣。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 댁들 딸내미 말한 거야.","JPN":"私はお前らの娘のことを言っているんだ。","ENG":"I'm talking about your daughter.","TWN":"我說的是你們的女兒。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"우, 우리 딸이요?","JPN":"う、うちの子？","ENG":"O-our daughter?","TWN":"我、我們的女兒？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 학교도 안 다니고 하루 열일곱 시간씩 돈만 버는 댁들 딸내미.","JPN":"そう。学校も通わせてもらえず、1日17時間も仕事をさせられているお前らの娘のことだ。","ENG":"That's right. The daughter you make work for 17 hours a day, not even sending her to school.","TWN":"沒錯。不上學，每天要去賺17個小時錢的…你女兒。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 정도로 튼튼하면 담보로 잡아 줄 만하지.","JPN":"そこまで丈夫なら担保としてもらっておいても悪くないだろう。","ENG":"A sturdy girl like that could be worth the collateral.","TWN":"身體看來不錯，可以作為抵押品。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"아니, 안 돼요! 안 돼! 걔 없으면 누가 저희 밑천을 벌어다 줘요!","JPN":"いや、駄目だ！　それだけは！　あの子がいないと俺らの稼ぎ口が無くなってしまうんだよ！","ENG":"No, you can't! No way! Who's going to earn our seed money if she's gone?","TWN":"不，不行！不行！沒有她，誰來給我們賺這些賭本！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"맞아요! 험한 일 하다 돈 못 벌어 올까 걱정돼서 용병 일도 안 시키는데......!","JPN":"そうよ！　外で危ない仕事をして怪我でもしたら働けなくなるのが心配で、傭兵の仕事もさせてないのに……！","ENG":"That's right! We won't even let her do mercenary work in case she gets injured and can't make money!","TWN":"對啊！我們擔心他做危險的事會沒命，可都沒讓她去做傭兵的工作呢……！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"난 댁들 허락 부탁한 적 없어.","JPN":"私はお前たちの許可を得たいと言ったか？","ENG":"I wasn't asking for your consent.","TWN":"我不是在徵求你們的同意。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L49_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FROLL_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"그렇게 하겠다고 통보했을 뿐이지.","JPN":"そうすると通告しただけだ。","ENG":"I was simply notifying you that I'll be taking her.","TWN":"我只是通知你們。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADE","text":{"KOREA":"아...... 아아......","JPN":"あ……ああ……","ENG":"Ah... Aah...","TWN":"啊……啊啊……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"빌어먹을...... 침식체가 어떻게 내 과거를 아는 거지?","JPN":"くそ……侵食体がどうして私の過去を知っている？","ENG":"Darn it... How does a C.O. know about my past?","TWN":"可惡……侵蝕體怎麼會知道我的過去？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이럴 때가 아냐. 당장 꼬맹이를 찾아서 이 이상한 곳을 벗어나야 돼.","JPN":"こうしている場合じゃない。すぐガキを見つけ出してこんな場所からさっさと離れないと。","ENG":"This isn't the time for reminiscing. I've got to find the kid and get out of this creepy joint.","TWN":"現在不是想這個的時候。要趕快找到小鬼，離開這裡才行。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>하찮은 미물치고는 제법이구나.</color>","JPN":"<color=#ff3636>下等な微物としては案外やるではないか。</color>","ENG":"<color=#ff3636>You are impressive for a mere mortal.</color>","TWN":"<color=#ff3636>雖然是微不足道的廢物，但還不錯。</color>"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 목소리는...... 지하에서 들었던?","JPN":"これは……地下で聞こえた声？","ENG":"That voice... Isn't it from the basement?","TWN":"這聲音……是在地下聽到的那個？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"나의 이름은 솔리키타티오.","JPN":"余の名はソリキタティオ。","ENG":"My name is Sollicitatio.","TWN":"我的名字是索爾奇塔提奧。 "},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>왕</color>의 계시를 전하는, 첫 번째 존재로다.","JPN":"<color=#ffd34c>王</color>の啓示を伝える、最初の存在である。","ENG":"I am the first being who delivers the revelations of <color=#ffd34c>the queen</color>.","TWN":"傳遞<color=#ffd34c>王</color>的啟示的第一人。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......왕이라고?","JPN":"……王だと？","ENG":"The queen?","TWN":"……王？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럼 난 마리 앙투아네트겠다. 흰둥아.","JPN":"それじゃあ、私はマリー・アントワネットだな、白い飼い犬。","ENG":"Then I'm Marie Antoinette. You creepy albino.","TWN":"那我這樣就是瑪麗·安託瓦內特了，小白。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"루이 16세 모가지가 날아간 지 200년도 지났는데 왕 타령은 시대에 뒤처진 거 아닌가?","JPN":"ルイ16世が首を落とされて200年以上経ってるのに、王だなんて時代遅れじゃないか？","ENG":"Don't you think it's getting a bit old to talk about queens? It's been centuries since Louis XVI lost his head, after all.","TWN":"路易十六已經死了200多年了，什麼王不王的，也太過於老土了吧？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"겁먹지 않은 척 허세를 부리는 꼴이 가엾기까지 하구나.","JPN":"恐れを隠すため虚勢を張る姿が実に哀れだな。","ENG":"The way you feign confidence almost elicits my pity.","TWN":"你假裝不害怕的樣子真是可憐。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 가소로운 카운터 워치의 힘으로 나를 감당할 수 있을 것이라 생각하느냐?","JPN":"そのくだらぬカウンターウォッチごときの力で余の力に耐えられるとでも思うか？","ENG":"Do you think you'd stand a chance against me with your mere Counter Watch?","TWN":"你以為憑那個可笑的制裁者能量環就能戰勝我嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너도 이미 알아차렸겠지. 자신이 부질없는 만용을 부리고 있다는 사실을.","JPN":"貴様もすでに気付いているだろう。己が蛮勇を振るっている事実を。","ENG":"You've probably realized it as well. Your resistance is futile.","TWN":"你應該也察覺到了吧，自己在做無用的掙扎。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래? 그렇게 대단한 분께서 왜 이런 짓을 하지?","JPN":"ああ、そうか？　そんなお偉いさんがなぜこんなことをする？","ENG":"Is that so? Why would someone so impressive like you do this then?","TWN":"是嗎？既然你這麼了不起，為什麼還做這種事？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"남의 죄책감을 간지럽히면서 흥분하는 이상 성욕인가?","JPN":"他人の罪悪感を煽って興奮する、異常性癖みたいなものか？","ENG":"Are you some sort of pervert who gets off on other people's guilty conscience?","TWN":"是喚起別人罪惡感，好讓自己興奮的變態欲望？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네가 왕의 계획에 방해되기 때문이다.","JPN":"貴様が王の計画の邪魔になるからだ。","ENG":"It is because you are an impediment to the queen's plans.","TWN":"因為你妨礙了王的計畫。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"수정을 손에 넣은 자에게 <color=#ffd34c>완전한 존재</color>로 거듭날 기회를 주고자 했건만......","JPN":"水晶を手に入れた者に<color=#ffd34c>完全なる存在</color>へと生まれ変わる機会を与えようとしたが……","ENG":"I sought to grant the chance to be reborn as <color=#ffd34c>a perfect being</color> to the one who found the crystal...","TWN":"本想給拿到水晶的人一個成為<color=#ffd34c>完整存在</color>的機會。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 아이는 내 목소리에 귀를 기울이지 않더구나.","JPN":"あの小娘は私の声に耳を貸さなかった。","ENG":"But the child did not heed my voice.","TWN":"但那個孩子聽不到我的聲音。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"수정이라고......?","JPN":"水晶……？","ENG":"Crystal?","TWN":"水晶……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"설마...... 지하에 들어갔을 때 꼬맹이한테 수작을 부린 건가?","JPN":"まさか……地下に入った時に、ガキに何か仕掛けたのか？","ENG":"You mean... you tried to get to the kid when we were underground?","TWN":"難道……進入地下的時候，對那個小鬼做了什麼？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그랬지. 하지만 그 아이의 시선은 너에게서 떨어지지 않더구나.","JPN":"うむ。しかしあの娘の視線は貴様から離れなかった。","ENG":"Indeed. But she would not take her eyes off of you.","TWN":"是啊，但那個孩子的視線一刻都沒離開你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그러니 우선은 너를 먼저 부숴 줄 수밖에.","JPN":"だから先に貴様を壊してやらねば。","ENG":"So I have no choice but to destroy you first.","TWN":"所以只能先從你下手。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 말 그대로 돌려 주지.","JPN":"その言葉、そのまま返してやる。","ENG":"Funny, I was about to say the same to you.","TWN":"那句話我原封不動地還給你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 아이는 내 거다.","JPN":"あれは私のものだ。","ENG":"The kid is mine.","TWN":"那個孩子是我的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"손가락 하나라도 건드린다면...... ","JPN":"指一本でも触れたら……","ENG":"If you so much as lay a finger on her... ","TWN":"如果你動她一根手指……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"부숴 버리겠어!","JPN":"ぶっ壊してやる！","ENG":"I will destroy you!","TWN":"我就讓你不得好死！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"큭......?!","JPN":"くっ……！？","ENG":"Ngh?!","TWN":"咳……？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"말도 안 돼...... 오메르타가 아무런 피해도 주지 못한다고?","JPN":"あり得ない……オメルタの攻撃がまったく効かないだと？","ENG":"No way... Omerta couldn't inflict any damage on you?","TWN":"不可能……奧梅爾塔竟然不能傷他分毫？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"재능은 있다만 그것뿐이군.","JPN":"才能はあるが、それだけだな。","ENG":"You are talented, but that is all.","TWN":"沒想到你只有這點能耐。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"부나방처럼 달려드는 어리석음이 참으로 가엾도다.","JPN":"蛾の火に赴くが如し、その愚かさが実に哀れで滑稽だ。","ENG":"You foolishly lunge towards your demise like a moth into the flames. How pitiful.","TWN":"飛蛾撲火，實在可憐啊。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"커헉......?!","JPN":"ぐあ……！？","ENG":"Ack?!","TWN":"呃啊……？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_08"},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"비명소리는 제법 깜찍하게 지저귀는구나.","JPN":"悲鳴は存外かわいいものだな。","ENG":"Your cries are rather pleasant, like the chirping of sparrows.","TWN":"慘叫聲還真是可愛啊。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그러나 네가 저지른 어리석은 행동의 대가는 쉽게 값을 치를 수 없다.","JPN":"だが、貴様が犯した愚かな行動の対価はそう簡単に払えぬ。","ENG":"But you shall pay dearly for your foolish behavior.","TWN":"但你愚蠢行為的代價絕不止於此。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"자아...... 더욱 치열하게, 더욱 필사적으로 덤벼 보아라.","JPN":"さあ……さらに熾烈に、さらに必死になってかかって来るがよい。","ENG":"Now... Come at me with every fiber of your being.","TWN":"來吧……使出你最猛烈、最致命的招數吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네가 부서지는 만큼, 그 아이도 더 쉽게 무너질 테니.","JPN":"貴様を壊すことで、あの小娘も容易に壊れていくだろう。","ENG":"For your utter destruction will only hasten the child's fall as well.","TWN":"把你毀了，那孩子就更容易垮掉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"콜록......! 취향이 꽤 별나시군......!","JPN":"ゴホッ……！　変わった好みだな……！","ENG":"*Cough!* You get off on the weirdest crap, don't you?","TWN":"咳咳……！你的喜好還真特別……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐야......? 하늘에...... 금이 가고 있어......?","JPN":"なんだ……？　空に……ひびが入った……？","ENG":"What? The sky... is crumbling?","TWN":"什麼……？天空……出現了裂縫……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"흥...... 방랑자의 소행인가. 성가신 것.","JPN":"ふん……放浪者の仕業か。厄介なやつめ。","ENG":"Hmpf... So the Wayfarer decided to intervene. What a nuisance.","TWN":"哼……是流浪者做的嗎？真是討厭。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이번에는 여기까지군.","JPN":"今回はここまでだな。","ENG":"I suppose that will have to do for today.","TWN":"這次就到此為止吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 기억해 두거라, 미물이여.","JPN":"だが覚えておくがよい、微物よ。","ENG":"But remember this, ye mortal.","TWN":"但你要記住，微不足道的廢物。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 계획을 거스르는 이상, 너에게 안식은 허락되지 않을 것이다.","JPN":"余の計画に逆らう以上、貴様に安息は許されないことを。","ENG":"As long as you stand in our way, you shall not be granted respite.","TWN":"你既然違背我的計畫，就不會允許你安息。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"포기해라. 너의 모든 것을.","JPN":"諦めろ、己のすべてを。","ENG":"You must surrender... everything.","TWN":"放棄吧，你的全部。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};